/// <summary>
/// Controller class for BOL Report
/// </summary>
class ETGBillofLadingReportController extends SrsReportRunController
{
}

Method.Source:
public static ETGBillofLadingReportController construct()
{
    return new ETGBillofLadingReportController();
}

public static void main(Args _args)
{
    ETGBillofLadingReportController controller = ETGBillofLadingReportController::construct();
    ETGBillofLadingReportContract contract;

    controller.parmArgs(_args);
    controller.parmReportName(ssrsReportStr(ETGBillof_LadingReport,BillOfLading));

    if(_args && _args.record())
    {
        ETGBillofLadingTable table = _args.record();
        contract = controller.parmReportContract().parmRdpContract();
        contract.parmBillNumber(table.BillNumber);
    }
    controller.startOperation();
}
